package com.example.user.data.datasource

import com.example.user.domain.entities.User
import io.ktor.client.HttpClient
import io.ktor.client.call.body
import io.ktor.client.request.post
import io.ktor.client.request.setBody
import io.ktor.http.ContentType
import io.ktor.http.contentType

class UserDataSourceImpl(private val httpClient: HttpClient) : UserDataSource {
    override suspend fun registerUser(user: User): User {
        // Implement network call using Ktor
        // Make sure you have models for DTOs in a real app
        val response = httpClient.post("https://api.example.com/register") {
            contentType(ContentType.Application.Json)
            setBody(user) // assuming user is serializable or we use DTO
        }
        return response.body() // Returns user object after parsing
    }
}

package com.example.user.data.datasource

import com.example.user.domain.entities.User
import com.example.user.data.models.toModel
import io.ktor.client.HttpClient
import io.ktor.client.call.body
import io.ktor.client.request.header
import io.ktor.client.request.post
import io.ktor.client.request.setBody
import io.ktor.http.ContentType
import io.ktor.http.contentType

class UserDataSourceImpl(private val httpClient: HttpClient) : UserDataSource {
    override suspend fun registerUser(user: User): User {
        val userModel = user.toModel()

        // Menggunakan Supabase Auth REST SDK Endpoint dengan Ktor (Ganti URL nya dgn project id km)
        val response = httpClient.post("https://[PROJECT_ID].supabase.co/auth/v1/signup") {
            contentType(ContentType.Application.Json)
            // Load key dr properties, kita tempel disini untuk reqnya
            header("apikey", "sb_publishable_kOWdZASPCIZNeAyWzrmG2w_mODE0iip") 
            header("Authorization", "Bearer sb_publishable_kOWdZASPCIZNeAyWzrmG2w_mODE0iip")
            setBody(userModel) 
        }

        // Supabase Auth biasanya akan ngasi data balik, di real-app response json akan diparsing ke domain
        // Misal disini kita kembalikan param asli saja dulu krn udh sukses reqnya
        return user 
    }
}

